      "domain_id": "JC:Link-Lifecycle-Engine",
      "responsibilities": [
        {
          "id": "LINK-LIF-01",
          "statement": "Purges valid deletion requests from Sharers from persistent storage and ephemeral cache."
        },
        {
          "id": "LINK-LIF-02",
          "statement": "Exports 100% of stored link data for a requesting user for GDPR Right to Access requests."
        },
        {
          "id": "LINK-LIF-03",
          "statement": "Generates notification attempts for every policy-expiry event before the expiry timestamp."
        }
      ],
