          "id": "PLATFORM-DR-01",
          "statement": "Achieves Recovery Time Objective (RTO) on full regional failure requiring restoration within 15 minutes."
        },
        {
          "id": "PLATFORM-DR-02",
          "statement": "Executes daily automated backups and replicates with zero integrity errors to disaster recovery storage."
        }
